class AccountFrozenError(BankError):
    def __init__(self, account_id):
        self.account_id = account_id
        # TODO: Call super().__init__ with message:
        # "Account ACC001 is frozen"
        pass


class InvalidAmountError(BankError):
    def __init__(self, amount):
        self.amount = amount
        # TODO: Call super().__init__ with message:
        # "Invalid amount: -50 (must be positive)"
        pass


# Test the exceptions
def withdraw(balance, amount, frozen=False):
    if amount <= 0:
        raise InvalidAmountError(amount)
    if frozen:
        raise AccountFrozenError("ACC001")
    if amount > balance:
        raise InsufficientFundsError(balance, amount)
    return balance - amount


for call in [
    (100, 30, False),   # success
    (80, 150, False),   # insufficient
    (100, 50, True),    # frozen
    (100, -50, False),  # invalid amount
]:
    try:
        result = withdraw(*call)
        print(f"Withdrew ${call[1]}, new balance: ${result}")
    except BankError as e:
        print(f"{type(e).__name__}: {e}")

