class AppError(Exception):
    pass

class NotFoundError(AppError):
    def __init__(self, item):
        super().__init__(f"{item} not found")
        self.item = item

try:
    raise NotFoundError("user:42")
except AppError as e:
    print(type(e).__name__)
    print(str(e))
    print(e.item)
